QueryScript.Source:
import java.util.ArrayList;
import java.util.Iterator;
import java.util.List;
import java.util.HashSet;
import java.util.Set;

import sailpoint.api.SailPointContext;
import sailpoint.object.Filter;
import sailpoint.object.IdentityRequest;
import sailpoint.object.IdentityRequestItem;
import sailpoint.object.QueryOptions;
import sailpoint.tools.GeneralException;
import sailpoint.tools.Util;

List value=new ArrayList();
value.add("WBLeaver");
List requestTypes = new ArrayList();
List ARIDfilters = new ArrayList();
List irIDFilters = new ArrayList();

Set s=new HashSet();	
requestTypes.add("WBLeaver");
requestTypes.add("IFCLeaver");
QueryOptions qo = new QueryOptions();
Filter LeaverFilters = null;
if(value != null )                 
LeaverFilters = Filter.and(Filter.in("type", value), Filter.and(Filter.eq("items.application", "SAP")));
else
LeaverFilters = Filter.and(Filter.in("type", requestTypes), Filter.and(Filter.eq("items.application", "SAP")));
qo.add(LeaverFilters);
Iterator iter = context.search(IdentityRequest.class, qo);
while (iter != null @and iter.hasNext()) {
IdentityRequest ir=(IdentityRequest)iter.next();

List iriLst= ir.getItems();
for(int i=0;i<iriLst.size();i++) {
IdentityRequestItem iri=(IdentityRequestItem)iriLst.get(i);
if(iri.getApplication().equalsIgnoreCase("SAP")){
s.add(ir.getName());
break;
}
}
}


Filter irFilter = (Filter.in("name",s));
irIDFilters.add(irFilter);
Util.flushIterator(iter);
Filter finalARfilter = Filter.or(irIDFilters);
QueryOptions finalQO = new QueryOptions();
finalQO.add(finalARfilter);
return finalQO;

