import sailpoint.object.Identity;
String orgCode= null;
String orgName=null;
if(value!=null)
{
Identity id = context.getObjectById(Identity.class, value);
if(null != request)
{
if(null != id)
{
if(id.getAttribute("ORG_CODE")!=null){
orgCode= id.getAttribute("ORG_CODE").toString();
if(orgCode.equalsIgnoreCase("0")) {
orgName="IFC";
}else if(orgCode.equalsIgnoreCase("1")) {
orgName="IBRD";
}else if(orgCode.equalsIgnoreCase("2")) {
orgName="MIGA";
}else if(orgCode.equalsIgnoreCase("5")) {
orgName="GEF";
}
}else{
orgName="User not active";
}
}
}
}
return orgName;

