import sailpoint.tools.Message;
import org.apache.commons.lang.StringUtils;
import sailpoint.object.QueryOptions;
import java.util.List;
import sailpoint.object.Filter;
import sailpoint.object.Identity;
import sailpoint.object.IdentityRequest;
import sailpoint.object.IdentityRequestItem;
import java.util.ArrayList;
import java.util.Iterator;
import sailpoint.tools.GeneralException;

QueryOptions qoName = new QueryOptions();
List propName = new ArrayList();
String opr = "";
Identity idn;
try {
idn = context.getObjectById(Identity.class, value);
qoName.add(Filter.eq("targetId", idn.getId()));
qoName.add(Filter.or(Filter.eq("type", "WBLeaver"), Filter.eq("type", "IFCLeaver")));
Iterator itr = context.search(IdentityRequest.class, qoName);
while (itr.hasNext()) {
IdentityRequest idRequest = (IdentityRequest) itr.next();
List idnRequestItemLst = idRequest.getItems();
for (int i = 0; i < idnRequestItemLst.size(); i++) {
IdentityRequestItem idnRequestItem = (IdentityRequestItem) idnRequestItemLst.get(i);
if(idnRequestItem!=null){
if (idnRequestItem.getApplication().equalsIgnoreCase("SAP")) {
if (!idnRequestItem.getOperation().equalsIgnoreCase("set")) {
List errLst = idnRequestItem.getErrors();
if(errLst!=null){
for (int k = 0; k < errLst.size(); k++) {
Message msg=(Message) errLst.get(k);
if(msg!=null) {
String errMsgStr = msg.getMessage();
propName.add(errMsgStr);
}
}
}
}
}
}
}
}
} catch (GeneralException e) {
e.printStackTrace();
}
return propName;
